from dataclasses import dataclass

@dataclass
class IncidentSignature:
    affected_system: str
    failure_category: str
    symptom_pattern: str
    trigger_type: str

    def matches(self, other: "IncidentSignature", threshold: int = 3) -> bool:
        # Count how many dimensions match
        match_count = sum([
            self.affected_system == other.affected_system,
            self.failure_category == other.failure_category,
            self.symptom_pattern == other.symptom_pattern,
            self.trigger_type == other.trigger_type,
        ])
        return match_count >= threshold

def extract_signature(incident_metadata: dict) -> IncidentSignature:
    return IncidentSignature(
        affected_system=incident_metadata["affected_system"],
        failure_category=incident_metadata["failure_category"],
        symptom_pattern=incident_metadata["symptom_pattern"],
        trigger_type=incident_metadata.get("trigger_type", "unknown"),
    )

def check_library_for_repeat(
    new_sig: IncidentSignature,
    postmortem_library: list[dict],
    match_threshold: int = 3,
) -> list[dict]:
    matches = []
    for pm in postmortem_library:
        prior_sig = extract_signature(pm)
        if new_sig.matches(prior_sig, threshold=match_threshold):
            # Check if prior action items were closed
            prior_actions = pm.get("action_items", [])
            open_actions = [a for a in prior_actions if a["status"] != "closed"]
            matches.append({
                "postmortem_id": pm["id"],
                "match_score": sum_match_dimensions(new_sig, prior_sig),
                "prior_actions_open": len(open_actions),
                "prior_actions_total": len(prior_actions),
            })
    return sorted(matches, key=lambda m: m["match_score"], reverse=True)

@dataclass
class PreventionVerification:
    action_item_id: str
    verification_method: str
    performed_by: str          # must not be the action item owner
    performed_at: str          # ISO 8601 datetime
    evidence_url: str          # staging test, chaos log, PR, etc.
    effective: bool            # did the prevention actually work?
    notes: str

def require_prevention_verification(
    action_item: object,
    verification: PreventionVerification,
) -> None:
    if verification.performed_by == action_item.owner:
        raise ValueError(
            "Prevention verification must be performed by someone other than the owner"
        )
    if not verification.evidence_url:
        raise ValueError("Verification requires an evidence URL")
    if not verification.effective:
        # Prevention failed — action item must be reopened
        raise RuntimeError(
            f"Prevention measure for {action_item.id} was not effective. "
            "Action item must be reopened with a new approach."
        )

def find_signature_clusters(
    postmortems: list[dict],
    min_cluster_size: int = 3,
) -> list[dict]:
    from collections import defaultdict
    clusters = defaultdict(list)
    for pm in postmortems:
        sig = extract_signature(pm)
        # Group by affected_system + failure_category as the primary cluster key
        key = f"{sig.affected_system}::{sig.failure_category}"
        clusters[key].append(pm["id"])
    return [
        {
            "cluster_key": key,
            "postmortem_ids": pms,
            "size": len(pms),
            "recommendation": "Review for systemic architectural change",
        }
        for key, pms in clusters.items()
        if len(pms) >= min_cluster_size
    ]
